    <script><![CDATA[var DEXMetricRulesUtils = Class.create();
var constants = sn_dex.DEXMetricRulesConstants.CONSTANTS;

// Static property for location fields to exclude
DEXMetricRulesUtils.LOCATION_FIELDS = [
    'state',
    'city',
    'country',
    'latitude',
    'longitude',
    'location',
    'street',
    'zip',
    'state_province',
    'postal_code',
    'map_coordinates',
    'address',
    'address2',
    'county',
    'region',
    'territory'
];

DEXMetricRulesUtils.METRIC_SOURCES = ["26ee2cb6433c7510cd629698c4b8f2c7", "59be2cb6433c7510cd629698c4b8f2df", "e2de2cb6433c7510cd629698c4b8f2c4"]; // Device, Web app, Installed app
DEXMetricRulesUtils.TABLE_REFERENCE_TAGS = {
    "sys_user": "93507cf6433c7510cd629698c4b8f25b",
    "cmdb_ci_computer": "2042e02a7736311009aafe39d3237070"
}

// Static property for enriched base fields
DEXMetricRulesUtils.ENRICHED_BASE_FIELDS = ['location', 'version'];

DEXMetricRulesUtils.prototype = {

    initialize: function() {

        this.isPEActive = this.isPEPluginActive();
    },

    /**
     * Analyzes the condition filter to determine which fields are enriched
     * @param {Object} dexData - The dex_data object containing condition filters
     * @returns {Object} Object containing enriched and non-enriched fields for each base table
     */
    getEnrichedFieldsStatus: function(dexData) {
        if (!dexData || !dexData.config_item_selection || !dexData.config_item_selection.condition_filter) {
            return {};
        }

        var result = {
            sys_user: {
                enriched: [],
                not_enriched: []
            },
            cmdb_ci_computer: {
                enriched: [],
                not_enriched: []
            }
        };

        // Get enriched fields map
        var enrichedFieldsMap = this._getEnrichedFieldsMap();

        dexData.config_item_selection.condition_filter.forEach(function(filter) {
            filter.conditions_data.forEach(function(condition) {
                // Process AND data
                this._processFieldEnrichment(condition.and_data, result, enrichedFieldsMap);

                // Process OR data
                condition.or_data.forEach(function(orData) {
                    this._processFieldEnrichment(orData, result, enrichedFieldsMap);
                }, this);
            }, this);
        }, this);

        return result;
    },

    /**
     * Check if adding these not_enriched fields would exceed the limit
     * @private
     * @param {Object} enrichmentStatus - Result from getEnrichedFieldsStatus
     * @returns {Object} - {exceeded: boolean, message: string}
     */
    _checkEnrichmentLimit: function(enrichmentStatus) {
        var oobConfigCount = Object.keys(DEXConstants.OOB_ENRICHMENT_CONFIG_IDS).length;
        var configLimit = parseInt(gs.getProperty(DEXConstants.PROPERTY.METRIC_ENRICHED_TAG_LIMIT, DEXConstants.ENRICHMENT_LIMIT.DEFAULT_ENRICHMENT_LIMIT));
        var maxRecords = oobConfigCount + configLimit;

        // Count existing records
        var grCount = new GlideAggregate(DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
        grCount.addAggregate(DEXConstants.AGGREGATES.COUNT);
        grCount.query();

        var existingCount = 0;
        if (grCount.next()) {
            existingCount = parseInt(grCount.getAggregate(DEXConstants.AGGREGATES.COUNT));
        }

        // Calculate available slots
        var availableSlots = maxRecords - existingCount;

        // Count total not_enriched fields
        var totalNotEnriched = 0;
        if (enrichmentStatus.sys_user && enrichmentStatus.sys_user.not_enriched) {
            totalNotEnriched += enrichmentStatus.sys_user.not_enriched.length;
        }
        if (enrichmentStatus.cmdb_ci_computer && enrichmentStatus.cmdb_ci_computer.not_enriched) {
            totalNotEnriched += enrichmentStatus.cmdb_ci_computer.not_enriched.length;
        }

        return {
            exceeded: totalNotEnriched > availableSlots,
            message: constants.ENRICHMENT_LIMIT_ERROR
        };
    },

    /**
    /**
     * Get a map of all enriched fields from dex_metric_enriched_tag table
     * @private
     * @returns {Object} Map of enriched fields by base table and field
     */
    _getEnrichedFieldsMap: function() {
        var enrichedFieldsMap = {};
        var enrichedGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
        enrichedGr.query();

        while (enrichedGr.next()) {
            var baseTable = enrichedGr.getValue('enrichment_base_table');
            var enrichWith = enrichedGr.getValue('enrich_with');
            if (baseTable && enrichWith) {
                if (!enrichedFieldsMap[baseTable]) {
                    enrichedFieldsMap[baseTable] = {};
                }
                if (!enrichedFieldsMap[baseTable][enrichWith]) {
                    enrichedFieldsMap[baseTable][enrichWith] = {};
                }
                // Store both base table and field input
                enrichedFieldsMap[baseTable][enrichWith][baseTable] = true;
            }
        }

        return enrichedFieldsMap;
    },

    /**
     * Process a single field condition to determine if it's enriched
     * @private
     * @param {Object} data - The field data containing base_field_input and field_input
     * @param {Object} result - The result object to store enriched/not_enriched fields
     * @param {Object} enrichedFieldsMap - Map of enriched fields from _getEnrichedFieldsMap
     */
    _processFieldEnrichment: function(data, result, enrichedFieldsMap) {
        if (!data || !data.base_field_input || !data.field_input) {
            return;
        }

        var baseTable = data.base_field_input;
        var fieldName = data.field_input;

        // Skip if we don't track this base table
        if (!result[baseTable]) {
            return;
        }

        // Check if field is already processed
        if (result[baseTable].enriched.indexOf(fieldName) > -1 ||
            result[baseTable].not_enriched.indexOf(fieldName) > -1) {
            return;
        }

        var isEnriched = false;

        // Check if field is self-reference
        if (data.reference_of === baseTable) {
            isEnriched = true;
        }
        // Check if the combination exists in enriched fields map
        else {
            isEnriched = !!(enrichedFieldsMap[data.base_field_input] &&
                enrichedFieldsMap[data.base_field_input][data.field_input] &&
                enrichedFieldsMap[data.base_field_input][data.field_input][data.base_field_input]);
        }

        // Add to appropriate array
        if (isEnriched) {
            result[baseTable].enriched.push(fieldName);
        } else {
            result[baseTable].not_enriched.push(fieldName);
        }
    },

    isPayloadLimitBreached: function(dexData, response) {

        if (JSON.stringify(dexData).length > 100000) {

            response.success = false;
            response.messageTitle = constants.ERROR_MESSAGE_TITLE;
            response.message = constants.CONDITION_LIMIT_REACHED_MESSAGE;
            response.messageType = constants.CRITICAL;
        }
        return response;
    },

    checkIfDuplicateRuleName: function(response, name, sysId) {
        var nameDuplicateCheck = 'name=' + GlideStringUtil.escapeQueryTermSeparator(name);

        if (sysId) {
            nameDuplicateCheck += '^sys_id!=' + GlideStringUtil.escapeQueryTermSeparator(sysId);
        }

        var existingRuleAGr = new GlideAggregate(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
        existingRuleAGr.addEncodedQuery(nameDuplicateCheck, true);
        existingRuleAGr.addAggregate('COUNT');
        existingRuleAGr.query();

        var count = 0;

        if (existingRuleAGr.next()) {

            count = parseInt(existingRuleAGr.getAggregate('COUNT'));
        }

        if (count > 0) {

            response.success = false;
            response.messageTitle = constants.ERROR_MESSAGE_TITLE;
            response.message = constants.RULE_NAME_DUPLICATE_MESSAGE;
            response.messageType = constants.CRITICAL;
            return response;
        }
        return response;
    },

    checkIfActiveRulesLimitExceeded: function(response) {

        var metricRulesAGr = new GlideAggregate(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
        metricRulesAGr.addAggregate('COUNT');
        metricRulesAGr.addQuery('status', 'active');
        metricRulesAGr.query();
        var count = 0;
        if (metricRulesAGr.next()) {
            count = parseInt(metricRulesAGr.getAggregate('COUNT'));
        }

        if (count >= constants.METRIC_RULES_LIMIT) {

            response.success = false;
            response.messageTitle = constants.RULE_LIMIT_REACHED;
            response.message = constants.RULE_LIMIT_REACHED_CONTENT;
            response.messageType = constants.CRITICAL;
            return response;
        }
        return response;
    },

    activateOrDeactivatePERecord: function(alertActionSysId, isactive) {

        var prenWizardUtils = new sn_pren.PrenWizardUtils();
        prenWizardUtils.activateDeactivateEngagement(alertActionSysId, isactive);
    },

    createNewMetricRule: function(dexData, alertActionSysId) {

        var response = {
            "success": true,
            "messageTitle": "",
            "message": "",
            "messageType": ""

        };
        try {
            response = this.isPayloadLimitBreached(dexData, response);
            if (!response.success) {

                return response;
            }

            // Check if a metric rule with the same name already exists
            response = this.checkIfDuplicateRuleName(response, dexData.activation.name);

            if (!response.success) {

                return response;
            }

            // Check if active rules limit exceeded
            if (dexData.activation.is_active) {
                response = this.checkIfActiveRulesLimitExceeded(response);
                if (!response.success) {
                    return response;
                }
            }

            // Insert data
            var metricRulesGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
            metricRulesGr.initialize(); // Initialize a new record

            if (alertActionSysId) {
                metricRulesGr.action = alertActionSysId;
                if (dexData.activation.is_active) {
                    this.activateOrDeactivatePERecord(alertActionSysId, true);
                }
            }

            // Set values from the JSON data
            metricRulesGr.name = dexData.activation.name;

            // Handle type assignment based on config_item_type and type
            var configItemType = dexData.config_item_selection.config_item_type;
            var ruleType = (dexData.config_item_selection && dexData.config_item_selection.hasOwnProperty(DEXConstants.DEX_METRIC_RULE_PROPERTIES.RULE_TYPE)) ? dexData.config_item_selection.rule_type : '';

            // If both config_item_type and type exist and it's a device event rule
            if (configItemType === DEXConstants.DEX_METRIC_RULE_TYPES.DEVICE && ruleType === DEXConstants.DEX_METRIC_RULE_TYPES.EVENT) {
                metricRulesGr.type = DEXConstants.DEX_METRIC_RULE_TYPES.EVENT;
            } else {
                // Otherwise use config_item_type for regular metric rules
                metricRulesGr.type = configItemType;
            }
            var config_itemsArray = dexData.config_item_selection.config_items;
            var applicationLabels = '';

            if (config_itemsArray.length == 0) {

                applicationLabels = 'N/A';
            } else {

                for (var i = 0; i < config_itemsArray.length; i++) {

                    applicationLabels += config_itemsArray[i].label;

                    if (i < config_itemsArray.length - 1) {

                        applicationLabels += ', ';
                    }
                }
            }
            metricRulesGr.applications = applicationLabels;
            metricRulesGr.status = dexData.activation.is_active ? 'active' : 'inactive';

            // Handle OS type and isNPVDI flag using common functions
            dexData = this._handleOSType(dexData);
            dexData = this._handleNPVDIFlag(dexData);

            metricRulesGr.dex_data = JSON.stringify(dexData); // Store the entire JSON data as a string

            if (dexData.alerts.alert_when.all_values.selected_option) {

                metricRulesGr.alert_time_interval = JSON.stringify({
                    type: 'all_values',
                    value: dexData.alerts.alert_when.all_values
                });
            } else if (dexData.alerts.alert_when.avg_values.selected_option) {

                metricRulesGr.alert_time_interval = JSON.stringify({
                    type: 'avg_values',
                    value: dexData.alerts.alert_when.avg_values
                });
            } else {

                metricRulesGr.alert_time_interval = ''; // Default value if no option is selected
            }

            // Extract alert types and insert into the "alert_types" column
            var alertTypesArray = dexData.alerts.alert_types;
            var alertTypeLabels = '';
            for (var j = 0; j < alertTypesArray.length; j++) {
                alertTypeLabels += alertTypesArray[j].alert_type;
                if (j < alertTypesArray.length - 1) {
                    alertTypeLabels += ', ';
                }
            }
            metricRulesGr.alert_types = alertTypeLabels;

            // Validate enrichment fields
            var enrichmentValidation = this._validateNewEnrichmentFields(dexData);
            if (!enrichmentValidation.success) {
                return enrichmentValidation;
            }

            // Insert the record
            // A canCreate() check is not performed here because the record is being created by a system process in background.
            var newRecordID = metricRulesGr.insert();

            if (newRecordID) {
                // Create enrichment records
                this._createEnrichmentRecords(enrichmentValidation.fieldsToAdd);
            } else {
                response.success = false;
                response.messageTitle = constants.ERROR_MESSAGE_TITLE;
                response.message = constants.FAILED_TO_CREATE_MR_RECORD;
                response.messageType = constants.CRITICAL;
            }

            return response;
        } catch (ex) {

            response.success = false;
            response.messageTitle = constants.ERROR_MESSAGE_TITLE;
            response.message = ex;
            response.messageType = constants.CRITICAL;
            return response;
        }
    },

    updateMetricRule: function(sysId, dexData, alertActionSysId) {

        var response = {
            "success": true,
            "messageTitle": "",
            "message": "",
            "messageType": ""

        };
        try {
            var existingRuleGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
            if (existingRuleGr.get(sysId)) {
                // Validate ACL rights before update
                if (!existingRuleGr.canWrite()) {
                    response.success = false;
                    response.messageTitle = constants.ERROR_MESSAGE_TITLE;
                    response.message = gs.getMessage('You do not have permission to update this metric rule.');
                    response.messageType = constants.CRITICAL;
                    return response;
                }

                // Get the old dexData for comparison
                var oldDexData = {};
                try {
                    oldDexData = JSON.parse(existingRuleGr.getValue('dex_data'));
                } catch (parseError) {
                    gs.error('Error parsing existing dex_data: ' + parseError);
                    // Continue with empty oldDexData if parsing fails
                }

                response = this.isPayloadLimitBreached(dexData, response);

                if (!response.success) {

                    return response;
                }
                response = this.checkIfDuplicateRuleName(response, dexData.activation.name, sysId);

                if (!response.success) {

                    return response;
                }

                // Check if active rules limit exceeded
                if (dexData.activation.is_active && existingRuleGr.status == "inactive") {
                    response = this.checkIfActiveRulesLimitExceeded(response);
                    if (!response.success) {
                        return response;
                    }
                }

                // Validate enrichment changes
                var enrichmentValidation = this._validateEnrichmentChanges(oldDexData, dexData, sysId);
                if (!enrichmentValidation.success) {
                    return enrichmentValidation;
                }

                if (this.isPEActive) {
                    var existingActionId = existingRuleGr.getValue("action");
                    if (alertActionSysId != existingActionId) {
                        if (existingActionId) {
                            var prenWizardUtils = new sn_pren.PrenWizardUtils();
                            prenWizardUtils.cleanUpEngagement(existingActionId);
                        }
                        if (alertActionSysId == "" || alertActionSysId == null) {
                            existingRuleGr.action = null;
                        } else {
                            existingRuleGr.action = alertActionSysId;
                            if (dexData.activation.is_active) {
                                this.activateOrDeactivatePERecord(alertActionSysId, true);
                            }
                        }
                    } else {
                        if (existingActionId) {
                            if (dexData.activation.is_active) {
                                this.activateOrDeactivatePERecord(alertActionSysId, true);
                            } else {
                                this.activateOrDeactivatePERecord(alertActionSysId, false);
                            }
                        }
                    }
                }

                // Update the existing record with new data
                existingRuleGr.name = dexData.activation.name;

                // Handle type assignment based on config_item_type and type
                var configItemType = dexData.config_item_selection.config_item_type;
                var ruleType = (dexData.config_item_selection && dexData.config_item_selection.hasOwnProperty(DEXConstants.DEX_METRIC_RULE_PROPERTIES.RULE_TYPE)) ? dexData.config_item_selection.rule_type : '';

                // If both config_item_type and type exist and it's a device event rule
                if (configItemType === DEXConstants.DEX_METRIC_RULE_TYPES.DEVICE && ruleType === DEXConstants.DEX_METRIC_RULE_TYPES.EVENT) {
                    existingRuleGr.type = DEXConstants.DEX_METRIC_RULE_TYPES.EVENT;
                } else {
                    // Otherwise use config_item_type for regular metric rules
                    existingRuleGr.type = configItemType;
                }

                var config_itemsArray = dexData.config_item_selection.config_items;
                var applicationLabels = '';

                if (config_itemsArray.length == 0) {

                    applicationLabels = 'N/A';
                } else {

                    for (var i = 0; i < config_itemsArray.length; i++) {

                        applicationLabels += config_itemsArray[i].label;

                        if (i < config_itemsArray.length - 1) {

                            applicationLabels += ', ';
                        }
                    }
                }
                existingRuleGr.applications = applicationLabels;

                existingRuleGr.status = dexData.activation.is_active ? 'active' : 'inactive';

                // Handle OS type and isNPVDI flag using common functions
                dexData = this._handleOSType(dexData);
                dexData = this._handleNPVDIFlag(dexData);

                existingRuleGr.dex_data = JSON.stringify(dexData); // Store the entire JSON data as a string

                if (dexData.alerts.alert_when.all_values.selected_option) {

                    existingRuleGr.alert_time_interval = JSON.stringify({
                        type: 'all_values',
                        value: dexData.alerts.alert_when.all_values
                    });
                } else if (dexData.alerts.alert_when.avg_values.selected_option) {

                    existingRuleGr.alert_time_interval = JSON.stringify({
                        type: 'avg_values',
                        value: dexData.alerts.alert_when.avg_values
                    });
                } else {

                    existingRuleGr.alert_time_interval = ''; // Default value if no option is selected
                }

                // Extract alert types and update the "alert_types" column
                var alertTypesArray = dexData.alerts.alert_types;
                var alertTypeLabels = '';

                for (var j = 0; j < alertTypesArray.length; j++) {

                    alertTypeLabels += alertTypesArray[j].alert_type;

                    if (j < alertTypesArray.length - 1) {
                        alertTypeLabels += ', ';
                    }
                }
                existingRuleGr.alert_types = alertTypeLabels;

                // Update the record
                var updateSuccess = existingRuleGr.update();

                if (updateSuccess) {
                    // After successful update, clean up unused enrichment fields
                    this._cleanupUnusedEnrichmentFields(oldDexData, dexData, sysId);

                    // Create enrichment records for new fields
                    this._createEnrichmentRecords(enrichmentValidation.fieldsToAdd);
                } else {
                    response.success = false;
                    response.messageTitle = constants.ERROR_MESSAGE_TITLE;
                    response.message = constants.FAILED_TO_UPDATE_MR_RECORD;
                    response.messageType = constants.CRITICAL;
                }
            } else {

                response.success = false;
                response.messageTitle = constants.ERROR_MESSAGE_TITLE;
                response.message = constants.RECORD_DOES_NOT_EXIST;
                response.messageType = constants.CRITICAL;
            }
            return response;
        } catch (ex) {

            response.success = false;
            response.messageTitle = constants.ERROR_MESSAGE_TITLE;
            response.message = ex;
            response.messageType = constants.CRITICAL;
            return response;
        }
    },

    deleteMetricRules: function(sysIds) {
        var errors = [];

        try {
            if (gs.nil(sysIds) || sysIds.length === 0) {
                errors.push(sn_i18n.Message.getMessage('sn_dex', 'No records are selected.'));
                return errors;
            }

            var metricRulesGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
            metricRulesGr.addQuery('sys_id', 'IN', sysIds);
            metricRulesGr.query();

            while (metricRulesGr.next()) {
                var sysId = metricRulesGr.getUniqueValue();

                // Get enrichment fields before deleting the rule
                var fields = this._getMetricRuleEnrichmentFields(sysId);

                // Delete the rule first
                if (!metricRulesGr.deleteRecord()) {
                    errors.push('Failed to delete metric rule: ' + sysId);
                    continue;
                }

                // Now check and cleanup enrichment fields
                this._cleanupEnrichmentFields(fields);
            }
        } catch (ex) {
            errors.push(ex);
            gs.error('Error in deleteMetricRules: ' + ex);
        }

        return errors;
    },

    isPEPluginActive: function() {
        return GlidePluginManager.isActive('com.snc.proactive_engagement') && gs.getProperty(DEXConstants.PROPERTY.ENABLE_DEX_PROACTIVE_ENGAGEMENT, 'true') === 'true';
    },

    fetchDEXMetricRulesData: function(sys_id) {

        var response = {
            "success": false,
            "error": "",
            "data": {
                "dex_data": {},
                "alert_action_data": {
                    "sys_id": "",
                    "short_description": ""
                }
            },
            "isPEPluginActive": false
        };

        try {

            if (!sys_id || gs.nil(sys_id)) {
                return response;
            }
            response.isPEPluginActive = this.isPEActive;
            if (sys_id != "-1") {
                var metricRulesGR = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
                metricRulesGR.get(sys_id);

                if (metricRulesGR.isValid()) {
                    response.success = true;
                    var dexData = JSON.parse(metricRulesGR.getValue('dex_data'));

                    // Remove auto-injected condition objects before returning to UI
                    if (dexData.config_item_selection && dexData.config_item_selection.condition_filter &&
                        Array.isArray(dexData.config_item_selection.condition_filter)) {

                        var reconstructedOsType = "";
                        var emptyCondition = {
                            "and_data": {
                                "base_field_input": "",
                                "field_input": "",
                                "operator_input": "",
                                "reference_of": "",
                                "validations": {
                                    "base_field": {"messages": [], "valid": true},
                                    "field": {"messages": [], "valid": true},
                                    "operator": {"messages": [], "valid": true},
                                    "value": {"messages": [], "valid": true}
                                },
                                "value_input": "",
                                "value_item": {}
                            },
                            "or_data": []
                        };

                        // Process each condition filter
                        for (var i = 0; i < dexData.config_item_selection.condition_filter.length; i++) {
                            var filter = dexData.config_item_selection.condition_filter[i];

                            if (filter.conditions_data && Array.isArray(filter.conditions_data)) {
                                for (var j = 0; j < filter.conditions_data.length; j++) {
                                    var condition = filter.conditions_data[j];

                                    // Strip isNPVDI condition (auto-injected by _handleNPVDIFlag)
                                    if (condition.and_data && condition.and_data.field_input === "isNPVDI") {
                                        if (filter.conditions_data.length === 1) {
                                            filter.conditions_data[j] = JSON.parse(JSON.stringify(emptyCondition));
                                        } else {
                                            filter.conditions_data.splice(j, 1);
                                            j--;
                                        }
                                    }
                                    // Strip OS condition (auto-injected by _handleOSType) and reconstruct os_type
                                    else if (condition.and_data && condition.and_data.field_input === "os") {
                                        if (!reconstructedOsType && condition.and_data.value_item && condition.and_data.value_item.id) {
                                            reconstructedOsType = condition.and_data.value_item.id;
                                        }
                                        if (filter.conditions_data.length === 1) {
                                            filter.conditions_data[j] = JSON.parse(JSON.stringify(emptyCondition));
                                        } else {
                                            filter.conditions_data.splice(j, 1);
                                            j--;
                                        }
                                    }
                                }
                            }
                        }

                        if (reconstructedOsType) {
                            dexData.config_item_selection.os_type = reconstructedOsType;
                        }
                    }

                    response.data.dex_data = dexData;
                    if (response.isPEPluginActive) {
                        var actionGR = new GlideRecord(sn_dex.DEXConstants.TABLE.SN_PREN_ISSUE_REGISTRY_TEMPLATE);
                        if (metricRulesGR.getValue("action")) {
                            actionGR.get(metricRulesGR.getValue("action"));
                            if (actionGR.isValid()) {
                                response.data.alert_action_data.sys_id = actionGR.getValue('sys_id');
                                response.data.alert_action_data.short_description = actionGR.getValue('short_description');
                            }
                        }
                    }
                } else {

                    response.error = constants.RECORD_NOT_FOUND_MESSAGE;
                }
            }

            return response;

        } catch (ex) {
            response.error = ex;
            return response;
        }
    },

    addOOBMetricRules: function() {

        var result = {
            has_error: false,
            external_message: ""
        };
        var sample_metric_rules = this._fetchSampleMetricRulesDexData();
        for (var i = 0; i < sample_metric_rules.length; i++) {
            var response = this.createNewMetricRule(sample_metric_rules[i]);
            if (!response.success) {
                result.has_error = true;
                result.external_message = result.external_message + response.message + " ";
            }
        }
        return result;
    },

