    getTableFields: function(tableNames) {
        var result = {};

        if (!Array.isArray(tableNames) || !tableNames.length)
            return result;

        try {
            for (var i = 0; i < tableNames.length; i++) {
                var tableName = tableNames[i];

                // Initialize categories for this table
                result[tableName] = [{
                    "id": "enriched",
                    "label": "Enriched fields",
                    "children": []
                }, {
                    "id": "not_enriched",
                    "label": "Non enriched fields",
                    "children": []
                }];

                // Create enriched fields map first
                var enrichedFieldsMap = {};
                var enrichedGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
                enrichedGr.query();
                while (enrichedGr.next()) {
                    var baseTable = enrichedGr.getValue('enrichment_base_table');
                    var enrichWith = enrichedGr.getValue('enrich_with');
                    if (baseTable && enrichWith) {
                        if (!enrichedFieldsMap[baseTable]) {
                            enrichedFieldsMap[baseTable] = {};
                        }
                        if (!enrichedFieldsMap[baseTable][enrichWith]) {
                            enrichedFieldsMap[baseTable][enrichWith] = {};
                        }
                        enrichedFieldsMap[baseTable][enrichWith][baseTable] = true;
                    }
                }

                var dictGr = new GlideRecord(sn_dex.DEXConstants.TABLE.SYS_DICTIONARY);
                dictGr.addQuery('name', tableName);
                dictGr.addQuery('internal_type', '!=', 'password');
                dictGr.addQuery('read_only', false);
                dictGr.addQuery('max_length', '<=', 200);
                dictGr.addQuery('element', 'NOT IN', DEXMetricRulesUtils.LOCATION_FIELDS.join(','));
                dictGr.addQuery('element', 'NOT LIKE', 'sys_%')
                    .addOrCondition('element', 'sys_id');
                dictGr.orderBy('column_label');
                dictGr.query();

                // Add None option before the loop
                var noneField = {
                    field_type: 'reference',
                    id: tableName === sn_dex.DEXConstants.TABLE.SYS_USER ? 'user' : tableName === sn_dex.DEXConstants.TABLE.CMDB_CI_COMPUTER ? 'device' : tableName,
                    is_enriched: tableName === sn_dex.DEXConstants.TABLE.SYS_USER ||
                        tableName === sn_dex.DEXConstants.TABLE.CMDB_CI_COMPUTER,
                    label: '-- None --',
                    reference_of: tableName,
                    supported_operators: [{
                            id: 'is',
                            label: 'is'
                        },
                        {
                            id: 'is_not',
                            label: 'is not'
                        }
                    ]
                };

                // Add None field to appropriate category
                if (noneField.is_enriched) {
                    result[tableName][0].children.push(noneField);
                } else {
                    result[tableName][1].children.push(noneField);
                }

                while (dictGr.next()) {
                    var fieldInfo = {};
                    var elementName = dictGr.getValue('element');

                    // Get field type
                    fieldInfo.field_type = dictGr.getValue('internal_type') || '';
                    // Check if field is enriched for this table
                    fieldInfo.is_enriched = !!(enrichedFieldsMap[tableName] &&
                            enrichedFieldsMap[tableName][elementName] &&
                            enrichedFieldsMap[tableName][elementName][tableName]) ||
                        (tableName === sn_dex.DEXConstants.TABLE.SYS_USER && elementName === 'user');

                    // Set reference table if field is reference type
                    fieldInfo.reference_of = fieldInfo.field_type === 'reference' ?
                        dictGr.getValue('reference') : '';

                    // Set supported operators based on field type
                    fieldInfo.supported_operators = [{
                            id: 'is',
                            label: 'is'
                        },
                        {
                            id: 'is_not',
                            label: 'is not'
                        }
                    ];

                    if (fieldInfo.field_type === 'string' && elementName !== 'os') {
                        fieldInfo.supported_operators.push({
                            id: 'contains',
                            label: 'contains'
                        });
                    }

                    if (fieldInfo.field_type === 'integer' || fieldInfo.field_type === 'float' ||
                        fieldInfo.field_type === 'decimal' || fieldInfo.field_type === 'glide_date' ||
                        fieldInfo.field_type === 'glide_date_time') {
                        fieldInfo.supported_operators.push({
                            id: 'is_equal_to',
                            label: 'is equal to'
                        }, {
                            id: 'is_not_equal_to',
                            label: 'is not equal to'
                        }, {
                            id: 'is_greater_than',
                            label: 'is greater than'
                        }, {
                            id: 'is_less_than',
                            label: 'is less than'
                        }, {
                            id: 'is_greater_than_or_equal_to',
                            label: 'is greater than or equal to'
                        }, {
                            id: 'is_less_than_or_equal_to',
                            label: 'is less than or equal to'
                        });
                    }

                    var field = {
                        id: elementName,
                        label: dictGr.getValue('column_label') || elementName,
                        is_enriched: fieldInfo.is_enriched,
                        field_type: fieldInfo.field_type,
                        supported_operators: fieldInfo.supported_operators,
                        reference_of: fieldInfo.reference_of
                    };

                    // Add field to appropriate category
                    if (fieldInfo.is_enriched) {
                        result[tableName][0].children.push(field);
                    } else {
                        result[tableName][1].children.push(field);
                    }
                }
            }
        } catch (error) {
            gs.error('Error in DEXMetricRulesUtils.getTableFields: ' + error);
        }

        // Add system properties to the result
        result._sysProps = {
            enableEnrichmentForNpVdis: gs.getProperty(sn_dex.DEXConstants.PROPERTY.ENABLE_ENRICH_FOR_NP_VDIS, 'false') === 'true',
            compareConfigForEnrichmentRefreshNpVdis: gs.getProperty(sn_dex.DEXConstants.PROPERTY.MR_EVAL_COMPARE_CONFIG_FOR_ENRICHMENT_REFRESH_NP_VDIS, 'false') === 'true'
        };

        return result;
    },

    getTableRecords: function(tableName, searchString, limit) {
        var result = [];

        try {
            if (!tableName) {
                return result;
            }

            limit = limit || 10; // Default limit of 10 records
            var gr = new GlideRecord(tableName);

            // Get display field for the table
            var displayField = this._getTableDisplayField(tableName);

            if (searchString && searchString.length > 0) {
                gr.addQuery(displayField, 'CONTAINS', searchString);
            }

            gr.setLimit(limit);
            gr.query();

            while (gr.next()) {
                result.push({
                    id: gr.getUniqueValue(),
                    label: gr.getValue(displayField)
                });
            }
        } catch (error) {
            gs.error('Error in DEXMetricRulesUtils.getTableRecords: ' + error);
        }

        return result;
    },

    _getTableDisplayField: function(tableName) {
        try {
            // First try to get the table's configured display field
            var tableGr = new GlideRecord(sn_dex.DEXConstants.TABLE.SYS_DB_OBJECT);
            tableGr.addQuery('name', tableName);
            tableGr.query();
            if (tableGr.next() && tableGr.getValue('display_field')) {
                return tableGr.getValue('display_field');
            }

            // Try common display fields in order of preference
            var commonFields = ['name', 'number', 'title', 'sys_id'];
            var dictGr = new GlideRecord(sn_dex.DEXConstants.TABLE.SYS_DICTIONARY);
            dictGr.addQuery('name', tableName);
            dictGr.addQuery('element', 'IN', commonFields.join(','));
            dictGr.orderBy('element');
            dictGr.query();

            while (dictGr.next()) {
                var element = dictGr.getValue('element');
                // Return the first matching field in our preferred order
                for (var i = 0; i < commonFields.length; i++) {
                    if (element === commonFields[i]) {
                        return element;
                    }
                }
            }
            // If nothing found, return empty string
            return '';
        } catch (error) {
            gs.error('Error in DEXMetricRulesUtils._getTableDisplayField: ' + error);
            return '';
        }
    },

    /**
     * Extract enrichment fields from dexData
     * @param {Object} dexData - The dex_data object
     * @returns {Array} Array of field objects with table and field properties
     */
    _extractEnrichmentFields: function(dexData) {
        var fields = [];

        // Extract fields from config_item_selection.condition_filter
        if (dexData && dexData.config_item_selection && dexData.config_item_selection.condition_filter) {
            var filters = dexData.config_item_selection.condition_filter;
            for (var i = 0; i < filters.length; i++) {
                if (filters[i].conditions_data) {
                    for (var j = 0; j < filters[i].conditions_data.length; j++) {
                        var conditionData = filters[i].conditions_data[j];
                        this._processConditionForEnrichment(conditionData, fields);
                    }
                }
            }
        }

        return fields;
    },

    /**
     * Process condition data to extract enrichment fields
     * @param {Object} conditionData - The condition data object
     * @param {Array} fields - Array to add extracted fields to
     */
    _processConditionForEnrichment: function(conditionData, fields) {
        // Process AND condition
        if (conditionData.and_data) {
            this._processFieldEnrichmentForExtraction(conditionData.and_data, fields);
        }

        // Process OR conditions
        if (conditionData.or_data) {
            for (var i = 0; i < conditionData.or_data.length; i++) {
                this._processFieldEnrichmentForExtraction(conditionData.or_data[i], fields);
            }
        }
    },

    /**
     * Process field enrichment data for extraction
     * @param {Object} data - The field data object
     * @param {Array} fields - Array to add extracted fields to
     */
    _processFieldEnrichmentForExtraction: function(data, fields) {
        if (!data || !data.base_field_input || !data.field_input) {
            return;
        }

        // Skip enrichment for user and device fields
        if (data.field_input === 'user' || data.field_input === 'device') {
            return;
        }

        // Check if this is an enrichment field
        if (data.base_field_input && data.field_input) {
            fields.push({
                table: data.base_field_input,
                field: data.field_input
            });
        }
    },

    /**
     * Find fields that were removed (in old but not in new)
     * @param {Array} oldFields - Array of old fields
     * @param {Array} newFields - Array of new fields
     * @returns {Array} Array of removed fields
     */
    _findRemovedFields: function(oldFields, newFields) {
        var removedFields = [];
        var seen = {}; // Track unique combinations

        for (var i = 0; i < oldFields.length; i++) {
            var oldField = oldFields[i];
            var found = false;

            for (var j = 0; j < newFields.length; j++) {
                if (oldField.table === newFields[j].table &&
                    oldField.field === newFields[j].field) {
                    found = true;
                    break;
                }
            }

            if (!found) {
                // Create unique key for this combination
                var key = oldField.table + '|' + oldField.field;
                if (!seen[key]) {
                    seen[key] = true;
                    removedFields.push(oldField);
                }
            }
        }

        return removedFields;
    },

    /**
     * Find fields that were added (in new but not in old)
     * @param {Array} oldFields - Array of old fields
     * @param {Array} newFields - Array of new fields
     * @returns {Array} Array of added fields
     */
    _findAddedFields: function(oldFields, newFields) {
        var addedFields = [];
        var seen = {}; // Track unique combinations

        for (var i = 0; i < newFields.length; i++) {
            var newField = newFields[i];
            var found = false;

            for (var j = 0; j < oldFields.length; j++) {
                if (newField.table === oldFields[j].table &&
                    newField.field === oldFields[j].field) {
                    found = true;
                    break;
                }
            }

            if (!found) {
                // Create unique key for this combination
                var key = newField.table + '|' + newField.field;
                if (!seen[key]) {
                    seen[key] = true;
                    addedFields.push(newField);
                }
            }
        }

        return addedFields;
    },

    /**
     * Check if a field is used in other metric rules
     * @param {String} baseTable - The base table name
     * @param {String} field - The field name
     * @param {String} currentRuleSysId - The sys_id of the current rule (to exclude)
     * @returns {Boolean} True if field is used in other rules
     */
    _isFieldUsedInOtherRules: function(baseTable, field, currentRuleSysId) {
        var rulesGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);

        // Exclude the current rule being updated
        if (currentRuleSysId) {
            rulesGr.addQuery('sys_id', '!=', currentRuleSysId);
        }

        rulesGr.query();

        while (rulesGr.next()) {
            try {
                var dexData = JSON.parse(rulesGr.getValue('dex_data'));
                var fields = this._extractEnrichmentFields(dexData);

                for (var i = 0; i < fields.length; i++) {
                    if (fields[i].table === baseTable && fields[i].field === field) {
                        return true; // Field is used in another rule
                    }
                }
            } catch (error) {
                gs.error('Error checking field usage in rule ' + rulesGr.getUniqueValue() + ': ' + error);
            }
        }

        return false; // Field is not used in any other rule
    },

    /**
     * Get the current count of enrichment tags
     * @returns {Number} Count of enrichment tags
     */
    _getCurrentEnrichmentCount: function() {
        var ga = new GlideAggregate(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
        ga.addAggregate('COUNT');
        ga.query();

        if (ga.next()) {
            return parseInt(ga.getAggregate('COUNT'));
        }

        return 0;
    },

    /**
     * Get the enrichment limit
     * @returns {Number} The enrichment limit
     */
    _getEnrichmentLimit: function() {
        var oobConfigCount = Object.keys(DEXConstants.OOB_ENRICHMENT_CONFIG_IDS).length;
        var configLimit = parseInt(gs.getProperty(DEXConstants.PROPERTY.METRIC_ENRICHED_TAG_LIMIT,
            DEXConstants.ENRICHMENT_LIMIT.DEFAULT_ENRICHMENT_LIMIT));
        return oobConfigCount + configLimit;
    },

    /**
     * Check if an enrichment tag is an OOB record
     * @param {String} sysId - The sys_id of the enrichment tag
     * @returns {Boolean} True if it's an OOB record
     */
    _isOOBEnrichmentTag: function(sysId) {
        return DEXConstants.OOB_ENRICHMENT_CONFIG_IDS.hasOwnProperty(sysId);
    },

    /**
     * Create enrichment records for new fields
     * @param {Array} fieldsToAdd - Array of fields to add
     */
    _createEnrichmentRecords: function(fieldsToAdd) {
        try {
            for (var i = 0; i < fieldsToAdd.length; i++) {
                var field = fieldsToAdd[i];

                // Check if enrichment record already exists
                var existingGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
                existingGr.addQuery('enrichment_base_table', field.table);
                existingGr.addQuery('enrich_with', field.field);
                existingGr.query();

                if (!existingGr.next()) {
                    // Get field label for tag name
                    var fieldLabel = this._getFieldLabel(field.table, field.field);
                    var tagName = field.table + '_' + field.field;
                    tagName = this._snakeCaseToCamelCase(tagName);
                    var tagDisplayName = fieldLabel || (field.table + ' ' + field.field);

                    if (!DEXMetricRulesUtils.TABLE_REFERENCE_TAGS[field.table])
                        throw new Error("Invalid base table to create enriched tag " + field.table);

                    // Create metric tag record first
                    var tagSysId = this._createMetricTag(tagName, tagDisplayName);

                    if (tagSysId) {
                        // Create enriched tag record
                        var enrichedTagGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
                        enrichedTagGr.initialize();
                        enrichedTagGr.reference_tag = DEXMetricRulesUtils.TABLE_REFERENCE_TAGS[field.table];
                        enrichedTagGr.enriched_tag = tagSysId;
                        enrichedTagGr.enrichment_base_table = field.table;
                        enrichedTagGr.enrich_with = field.field;

                        var enrichedTagSysId = enrichedTagGr.insert();
                        if (enrichedTagSysId) {
                            this._createSourceTagM2M(tagSysId);
                            gs.info('Created enrichment tag: ' + enrichedTagSysId +
                                ' (table: ' + field.table + ', field: ' + field.field + ')');
                        } else {
                            gs.error('Failed to create enrichment tag for table: ' +
                                field.table + ', field: ' + field.field);
                        }
                    }
                }
            }
        } catch (error) {
            gs.error('Error creating enrichment records: ' + error);
        }
    },

    _createSourceTagM2M: function(tagId) {
        if (!GlideStringUtil.isEligibleSysID(tagId))
            throw new Error("DEXMetricRulesUtils: Can not create source metric tag record. invalid tagId provided " + tagId);

        for (var sId in DEXMetricRulesUtils.METRIC_SOURCES) {
            var sourceTagGR = new GlideRecord(DEXConstants.TABLE.DEX_SOURCE_TAG_M2M);
            sourceTagGR.addQuery("source", DEXMetricRulesUtils.METRIC_SOURCES[sId]);
            sourceTagGR.addQuery("tag", tagId);
            sourceTagGR.query();
            if (!sourceTagGR.next()) {
                sourceTagGR.setValue("source", DEXMetricRulesUtils.METRIC_SOURCES[sId]);
                sourceTagGR.setValue("tag", tagId);
                sourceTagGR.insert();
            }
        }
    },

    _removeSourceTagM2M: function(tagId) {
        if (!GlideStringUtil.isEligibleSysID(tagId))
            return;

        gs.info("DEXMetricRulesUtils: Deleting source metric tag M2M records for - " + tagId);
        var sourceTagGR = new GlideRecord(DEXConstants.TABLE.DEX_SOURCE_TAG_M2M);
        sourceTagGR.addQuery("source", "IN", DEXMetricRulesUtils.METRIC_SOURCES);
        sourceTagGR.addQuery("tag", tagId);
        sourceTagGR.deleteMultiple();
    },

    /**
     * Create a metric tag record
     * @param {String} name - Internal name for the tag
     * @param {String} displayName - Display name for the tag
     * @returns {String} sys_id of the created tag or null if failed
     */
    _createMetricTag: function(name, displayName) {
        try {
            // Check if tag already exists
            var existingTag = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_TAG);
            existingTag.addQuery('name', name);
            existingTag.query();

            if (existingTag.next()) {
                return existingTag.getUniqueValue();
            }

            // Create new tag
            var tagGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_TAG);
            tagGr.initialize();
            tagGr.name = name;
            tagGr.display_name = displayName;
            tagGr.data_type = 't'; // Default to tokenized
            tagGr.persisted = false;

            var tagSysId = tagGr.insert();
            if (tagSysId) {
                gs.info('Created metric tag: ' + tagSysId + ' (' + name + ')');
                return tagSysId;
            } else {
                gs.error('Failed to create metric tag: ' + name);
                return null;
            }
        } catch (error) {
            gs.error('Error creating metric tag: ' + error);
            return null;
        }
    },

    /**
     * Get the label for a field
     * @param {String} tableName - The table name
     * @param {String} fieldName - The field name
     * @returns {String} The field label or null if not found
     */
    _getFieldLabel: function(tableName, fieldName) {
        try {
            var dictGr = new GlideRecord('sys_dictionary');
            dictGr.addQuery('name', tableName);
            dictGr.addQuery('element', fieldName);
            dictGr.query();

            if (dictGr.next()) {
                return dictGr.getValue('column_label') || null;
            }
            return null;
        } catch (error) {
            gs.error('Error getting field label: ' + error);
            return null;
        }
    },

    _snakeCaseToCamelCase: function(word) {
        if (!word)
            return word;
        try {
            var words = word.split("_");
            if (words.length == 1)
                return word;
            var firstWord = words.shift();
            return firstWord + words.map(function(w) {
                return w[0] && w[0].toUpperCase() + w.substring(1, w.length);
            }).join("");
        } catch (e) {
            gs.debug("DEXMetricRulesUtils: Error while converting " + word + " to camel case " + e);
            return word;
        }
    },

    /**
     * Clean up unused enrichment fields
     * @param {Object} oldDexData - The old dex_data
     * @param {Object} newDexData - The new dex_data
     * @param {String} currentRuleSysId - The sys_id of the current rule
     */
    _cleanupUnusedEnrichmentFields: function(oldDexData, newDexData, currentRuleSysId) {
        try {
            var oldFields = this._extractEnrichmentFields(oldDexData);
            var newFields = this._extractEnrichmentFields(newDexData);
            var fieldsToRemove = this._findRemovedFields(oldFields, newFields);

            for (var i = 0; i < fieldsToRemove.length; i++) {
                var field = fieldsToRemove[i];

                // Check if field is used in other rules
                if (!this._isFieldUsedInOtherRules(field.table, field.field, currentRuleSysId)) {
                    // Delete the enrichment tag
                    var enrichedTagGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
                    enrichedTagGr.addQuery('enrichment_base_table', field.table);
                    enrichedTagGr.addQuery('enrich_with', field.field);
                    enrichedTagGr.query();

                    while (enrichedTagGr.next()) {
                        // Check if it's not an OOB record
                        if (!this._isOOBEnrichmentTag(enrichedTagGr.getUniqueValue())) {
                            gs.info('Deleting unused enrichment tag: ' + enrichedTagGr.getUniqueValue() +
                                ' (table: ' + field.table + ', field: ' + field.field + ')');
                            var tagId = enrichedTagGr.getValue("enriched_tag");
                            if (enrichedTagGr.deleteRecord())
                                this._removeSourceTagM2M(tagId);
                        }
                    }
                }
            }
        } catch (error) {
            gs.error('Error cleaning up unused enrichment fields: ' + error);
        }
    },

    /**
     * Validate enrichment field changes for a metric rule update
     * @param {Object} oldDexData - Previous dex_data
     * @param {Object} newDexData - New dex_data
     * @param {String} currentRuleSysId - Current rule sys_id
     * @returns {Object} Response object with success, message, etc.
     */
    _validateEnrichmentChanges: function(oldDexData, newDexData, currentRuleSysId) {
        var response = {
            success: true,
            messageTitle: '',
            message: '',
            messageType: '',
            fieldsToAdd: [],
            fieldsToRemove: []
        };

        try {
            // Extract fields from old and new data
            var oldFields = this._extractEnrichmentFields(oldDexData);
            var newFields = this._extractEnrichmentFields(newDexData);

            // Find fields that will be removed and added
            var fieldsToRemove = this._findRemovedFields(oldFields, newFields);
            var fieldsToAdd = this._findAddedFields(oldFields, newFields);

            // Calculate actual deletions
            var actualDeletions = 0;
            for (var i = 0; i < fieldsToRemove.length; i++) {
                var field = fieldsToRemove[i];
                if (!this._isFieldUsedInOtherRules(field.table, field.field, currentRuleSysId)) {
                    actualDeletions++;
                }
            }

            // Validate fields against limit
            var validationResult = this._validateFieldsAgainstLimit(fieldsToAdd, actualDeletions);
            if (!validationResult.success) {
                response.success = false;
                response.messageTitle = validationResult.messageTitle;
                response.message = validationResult.message;
                response.messageType = validationResult.messageType;
                return response;
            }

            // Update fieldsToAdd to only include actually new fields
            fieldsToAdd = validationResult.actualNewFields;

            // Store the fields for later use
            response.fieldsToAdd = fieldsToAdd;
            response.fieldsToRemove = fieldsToRemove;
            return response;
        } catch (error) {
            response.success = false;
            response.messageTitle = constants.ERROR_MESSAGE_TITLE;
            response.message = 'Error validating enrichment changes: ' + error;
            response.messageType = constants.CRITICAL;
            return response;
        }
    },

    /**
     * Validate enrichment fields for a new metric rule
     * @param {Object} dexData - The dex_data object
     * @returns {Object} Response object with success, message, and fields to add
     */
    _validateNewEnrichmentFields: function(dexData) {
        var response = {
            success: true,
            messageTitle: '',
            message: '',
            messageType: '',
            fieldsToAdd: []
        };

        try {
            // Extract fields from dexData
            var fields = this._extractEnrichmentFields(dexData);

            // Remove duplicates
            var seen = {};
            var uniqueFields = [];

            for (var i = 0; i < fields.length; i++) {
                var field = fields[i];
                var key = field.table + '|' + field.field;

                if (!seen[key]) {
                    seen[key] = true;
                    uniqueFields.push(field);
                }
            }

            // Validate fields against limit
            var validationResult = this._validateFieldsAgainstLimit(uniqueFields, 0);
            if (!validationResult.success) {
                response.success = false;
                response.messageTitle = validationResult.messageTitle;
                response.message = validationResult.message;
                response.messageType = validationResult.messageType;
                return response;
            }

            // Only add fields that don't exist yet
            response.fieldsToAdd = validationResult.actualNewFields;
            return response;
        } catch (error) {
            response.success = false;
            response.messageTitle = constants.ERROR_MESSAGE_TITLE;
            response.message = 'Error validating new enrichment fields: ' + error;
            response.messageType = constants.CRITICAL;
            return response;
        }
    },

    /**
     * Get all enrichment fields used by a metric rule
     * @param {String} sysId - The metric rule sys_id
     * @returns {Array} Array of field objects with table and field properties
     */
    _getMetricRuleEnrichmentFields: function(sysId) {
        try {
            var fields = [];
            var ruleGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);

            if (ruleGr.get(sysId)) {
                var dexData = {};
                try {
                    dexData = JSON.parse(ruleGr.getValue('dex_data'));
                } catch (parseError) {
                    gs.error('Error parsing dex_data for rule ' + sysId + ': ' + parseError);
                    return fields;
                }

                fields = this._extractEnrichmentFields(dexData);
            }

            return fields;
        } catch (error) {
            gs.error('Error getting enrichment fields for rule ' + sysId + ': ' + error);
            return [];
        }
    },

    /**
     * Clean up enrichment fields that are no longer used
     * @param {Array} fields - Array of field objects with table and field properties
     */
    _cleanupEnrichmentFields: function(fields) {
        try {
            for (var i = 0; i < fields.length; i++) {
                var field = fields[i];

                // Check if field is used in other rules
                if (!this._isFieldUsedInOtherRules(field.table, field.field)) {
                    var enrichedTagGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
                    enrichedTagGr.addQuery('enrichment_base_table', field.table);
                    enrichedTagGr.addQuery('enrich_with', field.field);
                    enrichedTagGr.query();

                    while (enrichedTagGr.next()) {
                        if (!this._isOOBEnrichmentTag(enrichedTagGr.getUniqueValue())) {
                            gs.info('Deleting unused enrichment tag: ' + enrichedTagGr.getUniqueValue() +
                                ' (table: ' + field.table + ', field: ' + field.field + ')');
                            var tagId = enrichedTagGr.getValue("enriched_tag");
                            if (enrichedTagGr.deleteRecord())
                                this._removeSourceTagM2M(tagId);
                        }
                    }
                }
            }
        } catch (error) {
            gs.error('Error cleaning up enrichment fields: ' + error);
        }
    },

    /**
     * Updates dex_data field in metric rules to include base_field_input, reference_of mappings, and isNPVDI flag
     * @returns {Object} Result with success status and updated sys_ids
     */
    updateMetricRulesDexData: function() {
        var result = {
            success: true,
            updatedSysIds: [],
            baseFieldUpdated: [],
            npvdiUpdated: [],
            error: ''
        };

        try {
            var metricRulesGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_RULES);
            metricRulesGr.query();

            while (metricRulesGr.next()) {
                try {
                    var dexData = JSON.parse(metricRulesGr.getValue('dex_data'));
                    var modified = false;
                    var baseFieldModified = false;
                    var npvdiModified = false;

                    // Handle isNPVDI flag
                    if (!dexData.config_item_selection.hasOwnProperty('isNPVDI')) {
                        dexData.config_item_selection.isNPVDI = false; // Default to false
                        npvdiModified = true;
                        modified = true;

                        // Apply the _handleNPVDIFlag function to add VDI condition
                        var processedDexData = this._handleNPVDIFlag(dexData);
                        if (processedDexData) {
                            dexData = processedDexData;
                        }
                    }

                    var conditionFilter = dexData.config_item_selection.condition_filter;
                    for (var i = 0; i < conditionFilter.length; i++) {
                        var conditions = conditionFilter[i].conditions_data;
                        for (var j = 0; j < conditions.length; j++) {
                            // Handle and_data
                            var andData = conditions[j].and_data;
                            if (andData) {
                                var mappings = this._getFieldMappings(andData.field_input);

                                // Update base_field_input and reference_of
                                if (andData.base_field_input !== mappings.base ||
                                    andData.reference_of !== mappings.ref) {
                                    modified = true;
                                    baseFieldModified = true;
                                    andData.base_field_input = mappings.base;
                                    andData.reference_of = mappings.ref;
                                }

                                // Add validations object if missing
                                if (!andData.validations) {
                                    modified = true;
                                    andData.validations = {};
                                }

                                // Add base_field validation if missing
                                if (!andData.validations.base_field) {
                                    modified = true;
                                    andData.validations.base_field = {
                                        messages: [],
                                        valid: true
                                    };
                                }
                            }

                            // Handle or_data array
                            var orData = conditions[j].or_data;
                            for (var k = 0; k < orData.length; k++) {
                                var mappings = this._getFieldMappings(orData[k].field_input);

                                // Update base_field_input and reference_of
                                if (orData[k].base_field_input !== mappings.base ||
                                    orData[k].reference_of !== mappings.ref) {
                                    modified = true;
                                    baseFieldModified = true;
                                    orData[k].base_field_input = mappings.base;
                                    orData[k].reference_of = mappings.ref;
                                }

                                // Add validations object if missing
                                if (!orData[k].validations) {
                                    modified = true;
                                    orData[k].validations = {};
                                }

                                // Add base_field validation if missing
                                if (!orData[k].validations.base_field) {
                                    modified = true;
                                    orData[k].validations.base_field = {
                                        messages: [],
                                        valid: true
                                    };
                                }
                            }
                        }
                    }

                    if (modified) {
                        metricRulesGr.setValue('dex_data', JSON.stringify(dexData));
                        if (metricRulesGr.update()) {
                            var sysId = metricRulesGr.getUniqueValue();
                            result.updatedSysIds.push(sysId);

                            // Track which updates were made
                            if (baseFieldModified) {
                                result.baseFieldUpdated.push(sysId);
                            }
                            if (npvdiModified) {
                                result.npvdiUpdated.push(sysId);
                                gs.info('DEXMetricRulesUtils: updateMetricRulesDexData - Added NPVDI flag to metric rule: ' + sysId);
                            }

                            gs.info('DEXMetricRulesUtils: updateMetricRulesDexData - Updated metric rule: ' + sysId);
                        } else {
                            gs.error('DEXMetricRulesUtils: updateMetricRulesDexData - Failed to update metric rule: ' + metricRulesGr.getUniqueValue());
                        }
                    }
                } catch (parseError) {
                    gs.error('DEXMetricRulesUtils: updateMetricRulesDexData - Error processing metric rule ' + metricRulesGr.getUniqueValue() + ': ' + parseError);
                }
            }
        } catch (error) {
            result.success = false;
            result.error = error.toString();
            gs.error('DEXMetricRulesUtils: updateMetricRulesDexData - Error: ' + error);
        }

        return result;
    },

    /**
     * Get base_field_input and reference_of mappings for a field
     * @private
     * @param {String} fieldInput - The field input to get mappings for
     * @returns {Object} Object with base and ref mappings
     */
    _getFieldMappings: function(fieldInput) {
        var mappings = {
            'os': {
                base: sn_dex.DEXConstants.TABLE.CMDB_CI_COMPUTER,
                ref: ''
            },
            'user': {
                base: sn_dex.DEXConstants.TABLE.SYS_USER,
                ref: sn_dex.DEXConstants.TABLE.SYS_USER
            },
            'department': {
                base: sn_dex.DEXConstants.TABLE.SYS_USER,
                ref: sn_dex.DEXConstants.TABLE.CMN_DEPARTMENT
            },
            'location': {
                base: sn_dex.DEXConstants.FIELDS.LOCATION,
                ref: ''
            },
            'version': {
                base: sn_dex.DEXConstants.FILTERS.VERSION,
                ref: ''
            }
        };
        return mappings[fieldInput] || {
            base: '',
            ref: ''
        };
    },

    /**
     * Check if fields exist and validate against limit
     * @private
     * @param {Array} fields - Array of fields to check
     * @param {Number} deletionCount - Number of fields being deleted
     * @returns {Object} Result with success, error details, and actual new fields
     */
    _validateFieldsAgainstLimit: function(fields, deletionCount) {
        var result = {
            success: true,
            messageTitle: '',
            message: '',
            messageType: '',
            actualNewFields: []
        };

        try {
            // Check which fields are actually new
            for (var i = 0; i < fields.length; i++) {
                var field = fields[i];
                var existingGr = new GlideRecord(sn_dex.DEXConstants.TABLE.DEX_METRIC_ENRICHED_TAG);
                existingGr.addQuery('enrichment_base_table', field.table);
                existingGr.addQuery('enrich_with', field.field);
                existingGr.query();

                if (!existingGr.next()) {
                    result.actualNewFields.push(field);
                }
            }

            // Check if net new fields would exceed the limit
            var netNewFields = result.actualNewFields.length - (deletionCount || 0);
            if (netNewFields > 0) {
                var currentCount = this._getCurrentEnrichmentCount();
                var limit = this._getEnrichmentLimit();

                if (currentCount + netNewFields > limit) {
                    result.success = false;
                    result.messageTitle = constants.ERROR_MESSAGE_TITLE;
                    result.message = constants.ENRICHMENT_LIMIT_ERROR;
                    result.messageType = constants.CRITICAL;
                }
            }

            return result;
        } catch (error) {
            result.success = false;
            result.messageTitle = constants.ERROR_MESSAGE_TITLE;
            result.message = 'Error validating fields against limit: ' + error;
            result.messageType = constants.CRITICAL;
            return result;
        }
    },

    /**
     * Common function to handle NPVDI flag in dexData
     * @private
     * @param {Object} dexData - The dex_data object
     * @returns {Object} The modified dexData object
     */

    /**
     * Reads os_type from config_item_selection and adds/updates the OS condition
     * in each condition_filter group's conditions_data, preserving user-added conditions.
     * @private
     * @param {Object} dexData - The dex_data object
     * @returns {Object} The modified dexData object
     */
    _handleOSType: function(dexData) {
        if (!dexData.config_item_selection || !dexData.config_item_selection.condition_filter ||
            !Array.isArray(dexData.config_item_selection.condition_filter)) {
            return dexData;
        }
        var os_type = dexData.config_item_selection.os_type || "";
        if (!os_type) return dexData;
        var os_label = os_type === "windows" ? "Windows" : (os_type === "mac" || os_type === "macos") ? "Mac" : "";
        if (!os_label) return dexData;
        var os_id = os_type === "windows" ? "windows" : "mac";

        var osCondition = {
            "and_data": {
                "base_field_input": "cmdb_ci_computer",
                "field_input": "os",
                "operator_input": "is",
                "reference_of": "",
                "validations": {
                    "base_field": {"messages": [], "valid": true},
                    "field": {"messages": [], "valid": true},
                    "operator": {"messages": [], "valid": true},
                    "value": {"messages": [], "valid": true}
                },
                "value_input": os_label,
                "value_item": {"id": os_id, "label": os_label}
            },
            "or_data": []
        };

        for (var i = 0; i < dexData.config_item_selection.condition_filter.length; i++) {
            var filter = dexData.config_item_selection.condition_filter[i];
            if (!filter.conditions_data || !Array.isArray(filter.conditions_data)) continue;

            var hasOsCondition = false;
            for (var j = 0; j < filter.conditions_data.length; j++) {
                if (filter.conditions_data[j].and_data &&
                    filter.conditions_data[j].and_data.field_input === "os") {
                    filter.conditions_data[j].and_data.value_input = os_label;
                    filter.conditions_data[j].and_data.value_item = {"id": os_id, "label": os_label};
                    hasOsCondition = true;
                    break;
                }
            }

            if (!hasOsCondition) {
                if (filter.conditions_data.length === 1 &&
                    filter.conditions_data[0].and_data &&
                    (!filter.conditions_data[0].and_data.field_input || filter.conditions_data[0].and_data.field_input === "")) {
                    // Replace the empty placeholder entry with the OS condition
                    filter.conditions_data[0] = osCondition;
                } else {
                    // Append OS condition after user-added conditions
                    filter.conditions_data.push(JSON.parse(JSON.stringify(osCondition)));
                }
            }
        }

        delete dexData.config_item_selection.os_type;
        return dexData;
    },

    _handleNPVDIFlag: function(dexData) {
        if (dexData.config_item_selection && dexData.config_item_selection.condition_filter &&
            Array.isArray(dexData.config_item_selection.condition_filter)) {

            // Default to false if isNPVDI key doesn't exist
            var isNpVdiSelected = dexData.config_item_selection.isNPVDI === true;
            var stringValue = isNpVdiSelected ? "true" : "false";

            // Create VDI condition with simplified structure
            var vdiCondition = {
                "and_data": {
                    "base_field_input": "isNPVDI",
                    "field_input": "isNPVDI",
                    "operator_input": "is",
                    "reference_of": "",
                    "value_input": stringValue,
                    "value_item": {
                        "id": stringValue,
                        "label": stringValue
                    }
                },
                "or_data": []
            };

            // Process each condition filter
            for (var i = 0; i < dexData.config_item_selection.condition_filter.length; i++) {
                var filter = dexData.config_item_selection.condition_filter[i];

                if (filter.conditions_data && Array.isArray(filter.conditions_data)) {
                    // Check if VDI condition already exists to avoid duplicates
                    // This handles cases where fix scripts run multiple times or updates on existing rules
                    var hasVdiCondition = false;
                    for (var j = 0; j < filter.conditions_data.length; j++) {
                        if (filter.conditions_data[j].and_data &&
                            filter.conditions_data[j].and_data.field_input === "isNPVDI") {
                            hasVdiCondition = true;
                            break;
                        }
                    }

                    // Only add VDI condition if it doesn't already exist
                    if (!hasVdiCondition) {
                        // Check if there's only one element with empty values
                        if (filter.conditions_data.length === 1 &&
                            filter.conditions_data[0].and_data &&
                            (!filter.conditions_data[0].and_data.field_input || filter.conditions_data[0].and_data.field_input === "")) {

                            // Replace the empty element with our VDI condition
                            filter.conditions_data[0] = vdiCondition;
                        } else {
                            // Otherwise add as a new condition at the end (O(1) operation)
                            // Keeping it last makes removal easier during fetch operations
                            filter.conditions_data.push(JSON.parse(JSON.stringify(vdiCondition)));
                        }
                    }
                }
            }
        }

        return dexData;
    },

